    mod = _reload_autostart()

    calls: list[list[str]] = []

    def _fake_run(cmd: list[str], **_: object) -> object:
        calls.append(cmd)

        class R:
            returncode = 0

        return R()

    with patch("subprocess.run", side_effect=_fake_run):
        exit_code = mod.install(argv=[])

    unit = fake_home / ".config" / "systemd" / "user" / "agentpulse.service"
    assert exit_code == 0
    assert unit.exists()
    content = unit.read_text()
    assert "ExecStart=%h/.local/bin/agentpulse" in content
    assert any("daemon-reload" in " ".join(c) for c in calls)
    assert any("enable" in " ".join(c) and "agentpulse" in " ".join(c) for c in calls)


